# Expose usage summary as an API endpoint
from fastapi import FastAPI, Depends

app = FastAPI()

@app.get("/usage/{user_id}")
def get_usage(user_id: str, current_user=Depends(get_current_user)):
    if current_user.user_id != user_id and "admin" not in current_user.roles:
        raise HTTPException(status_code=403)
    summary = policy_engine.get_usage_summary(user_id)
    policy = TIER_POLICIES[current_user.tier]
    return {
        "user_id": user_id,
        "tier": current_user.tier,
        "usage": summary,
        "limits": {
            "requests_per_minute": policy.requests_per_minute,
            "tokens_per_day": policy.tokens_per_day,
            "max_cost_per_day_usd": policy.max_cost_per_day_usd,
        }
    }
